-- Step 42 editorial compare: fathom-vs-grain-vs-gong
-- Three-way AI meeting / sales-call intelligence shootout. The real fork is
-- org size: solo / SMB rep = Fathom free, 5-100-rep sales team = Grain
-- (Gong-lite at $15/seat/mo), 200+ reps with RevOps = Gong. Listicles bury
-- this in feature tables; we lead with it.

INSERT INTO tool_comparisons
  (tool_ids, slug, tldr, verdict, feature_analysis, pricing_analysis,
   use_cases, benchmarks, faqs, is_editorial, published_at, last_reviewed_at, view_count)
VALUES (
  ARRAY[
    (SELECT id FROM tools WHERE slug = $body0$fathom$body0$),
    (SELECT id FROM tools WHERE slug = $body1$grain$body1$),
    (SELECT id FROM tools WHERE slug = $body2$gong$body2$)
