  $body3$fathom-vs-grain-vs-gong$body3$,
  $body4$[
    {"dimension":"Best for","values":{"fathom":"Solo founders, SMB AEs, individual reps who want a free recorder + AI notes","grain":"5-100-rep sales teams who need clip-shareable knowledge libraries and light deal coaching","gong":"200+ rep orgs with RevOps, forecasting, and enterprise procurement"}},
    {"dimension":"Pricing floor (paid)","values":{"fathom":"$19/seat/mo Premium (Team Edition $29/seat/mo)","grain":"$15/seat/mo Business (billed annually)","gong":"Contact sales — public estimates $1,200-1,600/seat/year + platform fee"}},
